    private fun _setupOrDestroyPlayer(): Boolean{
        var mode: com.omnifret.gplayer.PlayerMode = this.settings.player.playerMode
        if (mode == com.omnifret.gplayer.PlayerMode.EnabledAutomatic)
        {
            var score: com.omnifret.gplayer.model.Score? = this.score
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(score)))
            {
                return false
            }
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(score!!?.backingTrack?.rawAudioFile)))
            {
                mode = com.omnifret.gplayer.PlayerMode.EnabledBackingTrack
            }
            else 
            {
                mode = com.omnifret.gplayer.PlayerMode.EnabledSynthesizer
            }
        }
        var newPlayer: com.omnifret.gplayer.synth.IGPlayerSynth? = null
        if (mode != this._actualPlayerMode)
        {
            this._destroyPlayer()
            this._updateCursors()
            when (mode)
            {
                com.omnifret.gplayer.PlayerMode.Disabled -> 
                {
                    newPlayer = null
                }
                com.omnifret.gplayer.PlayerMode.EnabledSynthesizer -> 
                {
                    newPlayer = this.uiFacade.createWorkerPlayer()
                }
                com.omnifret.gplayer.PlayerMode.EnabledBackingTrack -> 
                {
                    newPlayer = this.uiFacade.createBackingTrackPlayer()
                }
                com.omnifret.gplayer.PlayerMode.EnabledExternalMedia -> 
                {
                    newPlayer = com.omnifret.gplayer.synth.ExternalMediaPlayer(this.settings.player.bufferTimeInMilliseconds)
                }
                else -> { }
            }
        }
        else 
        {
            this._updateCursors()
            return false
        }
        this._actualPlayerMode = mode
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(newPlayer)))
        {
            return false
        }
        this._player.instance = newPlayer!!
        return false
    }
    
    /**
     * Re-creates the midi for the current score and loads it.
     */
    public fun loadMidiForScore(): Unit{
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.score)))
        {
            return
        }
        var score: com.omnifret.gplayer.model.Score = this.score!!
        com.omnifret.gplayer.Logger.debug("GPlayer", "Generating Midi")
        var midiFile: com.omnifret.gplayer.midi.MidiFile = com.omnifret.gplayer.midi.MidiFile()
        var handler: com.omnifret.gplayer.midi.GPlayerSynthMidiFileHandler = com.omnifret.gplayer.midi.GPlayerSynthMidiFileHandler(midiFile)
        var generator: com.omnifret.gplayer.midi.MidiFileGenerator = com.omnifret.gplayer.midi.MidiFileGenerator(score, this.settings, handler)
        var startIndex: Double = com.omnifret.gplayer.model.ModelUtils.computeFirstDisplayedBarIndex(score, this.settings)
        var endIndex: Double = com.omnifret.gplayer.model.ModelUtils.computeLastDisplayedBarIndex(score, this.settings, startIndex)
        generator.tickLookup.multiBarRestInfo = com.omnifret.gplayer.model.ModelUtils.buildMultiBarRestInfo(this.tracks, startIndex, endIndex)
        generator.applyTranspositionPitches = false
        generator.generate()
        this._tickCache = generator.tickLookup
        this._tickCache!!.playbackRange = this.playbackRange
        this._onMidiLoad(midiFile)
        var player: com.omnifret.gplayer.synth.GPlayerSynthWrapper = this._player
        player.midiTickShift = handler.tickShift
        player.loadMidiFile(midiFile)
        player.loadBackingTrack(score)
        player.updateSyncPoints(generator.syncPoints)
        player.applyTranspositionPitches(generator.transpositionPitches)
    }
    
