        var currentHandler: com.omnifret.gplayer.IScrollHandler? = this._defaultScrollHandler
        var scrollMode: com.omnifret.gplayer.ScrollMode = this.settings.player.scrollMode
        var isVertical: Boolean = com.omnifret.gplayer.Environment.getLayoutEngineFactory(this.settings.display.layoutMode).vertical
