        var previousBeat: com.omnifret.gplayer.midi.MidiTickLookupFindBeatResult? = this._currentBeat
        var previousCache: com.omnifret.gplayer.rendering.utils.BoundsLookup? = this._previousCursorCache
        var previousState: com.omnifret.gplayer.synth.PlayerState? = this._previousStateForCursor
        if (!forceUpdate && beat == previousBeat?.beat && cache!! == previousCache && previousState!! == this._player.state && previousBeat!!?.start == lookupResult.start)
        {
            return
        }
        var beatBoundings: com.omnifret.gplayer.rendering.utils.BeatBounds? = cache!!.findBeat(beat)
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beatBoundings)))
        {
