            this._internalCursorUpdateBeat(
                lookupResult
                , 
                stop
                , 
                cache!!
                , 
                beatBoundings!!
                , 
                shouldScroll
                , 
                cursorSpeed
                , 
                forceUpdate
            
            )
        }
        )
    }
    
