            }
            var relX: Double = e.getX(this.canvasElement)
            var relY: Double = e.getY(this.canvasElement)
            var beat: com.omnifret.gplayer.model.Beat? = this._renderer.boundsLookup?.getBeatAtPos(relX, relY) 
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat)))
            {
                this._onBeatMouseMove(e, beat!!)
                if (this._isNoteMouseDown)
                {
                    var note: com.omnifret.gplayer.model.Note? = this._renderer.boundsLookup?.getNoteAtPos(beat!!, relX, relY)
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        this._onNoteMouseMove(e, note!!)
                    }
                }
            }
        }
        )
        this.canvasElement.mouseUp.on(fun(e: com.omnifret.gplayer.platform.IMouseEventArgs): Unit{
            if (!this._isBeatMouseDown)
            {
                return
            }
            if (this.settings.player.enableUserInteraction)
            {
                e.preventDefault()
            }
            var relX: Double = e.getX(this.canvasElement)
            var relY: Double = e.getY(this.canvasElement)
            var beat: com.omnifret.gplayer.model.Beat? = this._renderer.boundsLookup?.getBeatAtPos(relX, relY) 
            this._onBeatMouseUp(e, beat)
            if (this._isNoteMouseDown)
