                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat)))
                {
                    var note: com.omnifret.gplayer.model.Note? = this._renderer.boundsLookup?.getNoteAtPos(beat!!, relX, relY) 
                    this._onNoteMouseUp(e, note)
                }
                else 
                {
                    this._onNoteMouseUp(e, null)
                }
            }
        }
        )
        this._renderer.postRenderFinished.on(fun(): Unit{
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._selectionStart)) || !this._hasCursor || !this.settings.player.enableUserInteraction)
            {
                return
            }
            this._cursorSelectRange(this._selectionStart!!, this._selectionEnd)
        }
        )
    }
    
