    private fun _onPlayerStateChanged(e: com.omnifret.gplayer.synth.PlayerStateChangedEventArgs): Unit{
        if (this._isDestroyed)
        {
            return
        }
        if (!e.stopped && e.state == com.omnifret.gplayer.synth.PlayerState.Paused)
        {
            var currentBeat: com.omnifret.gplayer.midi.MidiTickLookupFindBeatResult? = this._currentBeat
            var tickCache: com.omnifret.gplayer.midi.MidiTickLookup? = this._tickCache
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(currentBeat)) && com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(tickCache))))
            {
                this._player.tickPosition = tickCache!!.getBeatStart(currentBeat!!.beat)
                this.scrollToCursor()
            }
        }
        this.uiFacade.triggerEvent(this.container, "playerStateChanged", e)
    }
    
