    /**
     * Starts the audio export for the currently loaded song.
     * @param options The export options.
     */
    public suspend fun exportAudio(options: com.omnifret.gplayer.synth.AudioExportOptions): com.omnifret.gplayer.synth.IAudioExporter{
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.score)))
        {
            throw com.omnifret.gplayer.GPlayerError(com.omnifret.gplayer.GPlayerErrorType.General, "No song loaded")
        }
        var exporter: com.omnifret.gplayer.synth.IAudioExporterWorker
        when (this._actualPlayerMode)
        {
            com.omnifret.gplayer.PlayerMode.EnabledSynthesizer -> 
            {
                exporter = this.uiFacade.createWorkerAudioExporter(this._player.instance!!)
            }
            else -> 
            {
                exporter = this.uiFacade.createWorkerAudioExporter(null)
            }
        }
        var score: com.omnifret.gplayer.model.Score = this.score!!
        var midiFile: com.omnifret.gplayer.midi.MidiFile = com.omnifret.gplayer.midi.MidiFile()
        var handler: com.omnifret.gplayer.midi.GPlayerSynthMidiFileHandler = com.omnifret.gplayer.midi.GPlayerSynthMidiFileHandler(midiFile)
        var generator: com.omnifret.gplayer.midi.MidiFileGenerator = com.omnifret.gplayer.midi.MidiFileGenerator(score, this.settings, handler)
        generator.applyTranspositionPitches = false
        generator.generate()
        var optionsWithChannels: com.omnifret.gplayer.synth.AudioExportOptions = com.omnifret.gplayer.synth.AudioExportOptions()
        optionsWithChannels.soundFonts = options.soundFonts
        optionsWithChannels.sampleRate = options.sampleRate
        optionsWithChannels.useSyncPoints = options.useSyncPoints
        optionsWithChannels.masterVolume = options.masterVolume
        optionsWithChannels.metronomeVolume = options.metronomeVolume
        optionsWithChannels.playbackRange = options.playbackRange
        for ((trackIndex, volume) in options.trackVolume)
        {
            if (trackIndex < this.score!!.tracks.length)
            {
                var track: com.omnifret.gplayer.model.Track = this.score!!.tracks[(trackIndex).toInt()]
                optionsWithChannels.trackVolume.set(track.playbackInfo.primaryChannel, volume)
                optionsWithChannels.trackVolume.set(track.playbackInfo.secondaryChannel, volume)
            }
        }
        for ((trackIndex, semitones) in options.trackTranspositionPitches)
        {
            if (trackIndex < this.score!!.tracks.length)
            {
                var track: com.omnifret.gplayer.model.Track = this.score!!.tracks[(trackIndex).toInt()]
                optionsWithChannels.trackTranspositionPitches.set(track.playbackInfo.primaryChannel, semitones)
                optionsWithChannels.trackTranspositionPitches.set(track.playbackInfo.secondaryChannel, semitones)
            }
        }
        exporter.initialize(optionsWithChannels, midiFile, generator.syncPoints, generator.transpositionPitches)
        return exporter
    }
    
