 */
@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
public class PlaybackHighlightChangeEventArgs: com.omnifret.gplayer.core.IRecord
{
    /**
     * The beat where the selection starts. undefined if there is no selection.
     */
    public var startBeat: com.omnifret.gplayer.model.Beat? = null
    
    /**
     * The bounds of the start beat to determine its location and size.
     */
    public var startBeatBounds: com.omnifret.gplayer.rendering.utils.BeatBounds? = null
    
    /**
     * The beat where the selection ends. undefined if there is no selection.
     */
    public var endBeat: com.omnifret.gplayer.model.Beat? = null
    
    /**
     * The bounds of the end beat to determine its location and size.
     */
    public var endBeatBounds: com.omnifret.gplayer.rendering.utils.BeatBounds? = null
    
    /**
     * A list of the individual rectangular areas where highlight blocks are placed.
     * If a selection spans multiple lines this array will hold all items.
     */
    public var highlightBlocks: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.rendering.utils.Bounds>? = null
    
    public constructor(startBeat: com.omnifret.gplayer.model.Beat? = null, startBeatBounds: com.omnifret.gplayer.rendering.utils.BeatBounds? = null, endBeat: com.omnifret.gplayer.model.Beat? = null, endBeatBounds: com.omnifret.gplayer.rendering.utils.BeatBounds? = null, highlightBlocks: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.rendering.utils.Bounds>? = null){
        this.startBeat = startBeat
        this.startBeatBounds = startBeatBounds
        this.endBeat = endBeat
        this.endBeatBounds = endBeatBounds
        this.highlightBlocks = highlightBlocks
    }
    
}

